1	<!DOCTYPE HTML>
2	<html lang="en">
3	<head>
4	  <meta charset="UTF-8">
5	  <title>PathFinding.js — Scenario Builder</title>
6	  <link rel="stylesheet" href="./css/style.css">
7	  <link rel="stylesheet" href="./lib/themes/jquery.ui.all.css">
8	  <style>
9	    /* ── Scenario builder layout ───────────────────────────────── */
10	    body { margin: 0; padding: 0; font-family: Arial, sans-serif; background: #1a1a2e; color: #eee; }
11	
12	    #draw_area { display: block; }
13	
14	    #scenario_panel {
15	      position: fixed;
16	      top: 10px;
17	      right: 10px;
18	      width: 240px;
19	      background: #16213e;
20	      border: 1px solid #0f3460;
21	      border-radius: 6px;
22	      padding: 12px;
23	      z-index: 100;
24	      box-shadow: 0 4px 16px rgba(0,0,0,0.5);
25	    }
26	
27	    #scenario_panel h2 {
28	      margin: 0 0 12px 0;
29	      font-size: 14px;
30	      color: #e94560;
31	      text-transform: uppercase;
32	      letter-spacing: 1px;
33	    }
34	
35	    .ctrl-group { margin-bottom: 12px; }
36	    .ctrl-group label {
37	      display: block;
38	      font-size: 11px;
39	      color: #aaa;
40	      margin-bottom: 4px;
41	      text-transform: uppercase;
42	      letter-spacing: 0.5px;
43	    }
44	
45	    .ctrl-group select,
46	    .ctrl-group input[type=number] {
47	      width: 100%;
48	      box-sizing: border-box;
49	      background: #0f3460;
50	      color: #eee;
51	      border: 1px solid #1a4a7a;
52	      border-radius: 4px;
53	      padding: 5px 8px;
54	      font-size: 12px;
55	    }
56	
57	    .ctrl-group input[type=range] {
58	      width: 100%;
59	      box-sizing: border-box;
60	      accent-color: #e94560;
61	    }
62	
63	    .speed-value { font-size: 11px; color: #aaa; text-align: right; }
64	
65	    .grid-size-row { display: flex; gap: 6px; align-items: center; }
66	    .grid-size-row input { flex: 1; }
67	    .grid-size-row span { color: #aaa; font-size: 12px; }
68	
69	    .btn-row { display: flex; gap: 6px; }
70	    .btn-row .btn { flex: 1; }
71	
72	    .btn {
73	      display: block;
74	      width: 100%;
75	      padding: 7px 0;
76	      background: #0f3460;
77	      color: #eee;
78	      border: 1px solid #1a4a7a;
79	      border-radius: 4px;
80	      font-size: 12px;
81	      cursor: pointer;
82	      text-align: center;
83	      transition: background 0.15s;
84	    }
85	    .btn:hover { background: #1a4a7a; }
86	    .btn.primary { background: #e94560; border-color: #e94560; font-weight: bold; }
87	    .btn.primary:hover { background: #c73652; }
88	    .btn.danger { background: #553; border-color: #776; }
89	    .btn.danger:hover { background: #776; }
90	
91	    #status_bar {
92	      position: fixed;
93	      bottom: 10px;
94	      left: 50%;
95	      transform: translateX(-50%);
96	      background: rgba(22,33,62,0.9);
97	      border: 1px solid #0f3460;
98	      border-radius: 4px;
99	      padding: 6px 16px;
100	      font-size: 12px;
101	      color: #aaa;
102	      pointer-events: none;
103	    }
104	  </style>
105	</head>
106	<body>
107	
108	<div id="draw_area"></div>
109	
110	<div id="scenario_panel">
111	  <h2>Scenario Builder</h2>
112	
113	  <!-- Algorithm selector -->
114	  <div class="ctrl-group">
115	    <label for="algo_select">Algorithm</label>
116	    <select id="algo_select"></select>
117	  </div>
118	
119	  <!-- Preset map selector -->
120	  <div class="ctrl-group">
121	    <label for="preset_select">Preset Map</label>
122	    <select id="preset_select">
123	      <option value="">— choose preset —</option>
124	    </select>
125	  </div>
126	
127	  <!-- Grid size -->
128	  <div class="ctrl-group">
129	    <label>Grid Size</label>
130	    <div class="grid-size-row">
131	      <input type="number" id="grid_width"  min="5" max="50" value="15">
132	      <span>×</span>
133	      <input type="number" id="grid_height" min="5" max="50" value="15">
134	    </div>
135	  </div>
136	
137	  <!-- Speed slider -->
138	  <div class="ctrl-group">
139	    <label>Animation Speed — <span id="speed_label">200 ops/s</span></label>
140	    <input type="range" id="speed_slider" min="10" max="1000" value="200" step="10">
141	  </div>
142	
143	  <!-- Primary action buttons -->
144	  <div class="ctrl-group">
145	    <button class="btn primary" id="btn_find_path">Find Path</button>
146	  </div>
147	
148	  <div class="ctrl-group btn-row">
149	    <button class="btn danger" id="btn_clear">Clear</button>
150	    <button class="btn" id="btn_apply_size">Resize Grid</button>
151	  </div>
152	
153	  <!-- Save / Load -->
154	  <div class="ctrl-group btn-row">
155	    <button class="btn" id="btn_save">Save Scenario</button>
156	    <button class="btn" id="btn_load">Load Scenario</button>
157	  </div>
158	
159	  <!-- Hidden file input for load -->
160	  <input type="file" id="file_input" accept=".json" style="display:none">
161	</div>
162	
163	<div id="status_bar">Draw walls · Drag start (green) and end (red) nodes</div>
164	
165	<!-- Dependencies -->
166	<script src="./lib/raphael-min.js"></script>
167	<script src="./lib/es5-shim.min.js"></script>
168	<script src="./lib/jquery-1.7.2.min.js"></script>
169	<script src="./lib/state-machine.min.js"></script>
170	<script src="./lib/async.min.js"></script>
171	
172	<script src="./lib/ui/jquery.ui.core.min.js"></script>
173	<script src="./lib/ui/jquery.ui.widget.min.js"></script>
174	<script src="./lib/ui/jquery.ui.mouse.min.js"></script>
175	<script src="./lib/ui/jquery.ui.draggable.min.js"></script>
176	
177	<script src="./lib/pathfinding-browser.min.js"></script>
178	
179	<script src="./js/view.js"></script>
180	<script src="./js/scenario-controls.js"></script>
181	<script>
182	/**
183	 * Scenario Builder — wires ScenarioControls config to View + PF.
184	 * Minimal controller; leans on existing View for rendering.
185	 */
186	(function() {
187	    var SC     = ScenarioControls;
188	    var grid   = null;
189	    var startX = 1, startY = 1, endX = 13, endY = 13;
190	    var opsPerSecond = SC.SPEED_CONFIG.default;
191	    var isSearching  = false;
192	    var operations   = [];
193	    var animTimer    = null;
194	
195	    // ── Populate algorithm dropdown ────────────────────────────────────────
196	    var $algoSelect = $('#algo_select');
197	    SC.ALGORITHMS.forEach(function(algo) {
198	        $('<option>').val(algo.id).text(algo.label).appendTo($algoSelect);
199	    });
200	
201	    // ── Populate preset dropdown ───────────────────────────────────────────
202	    var $presetSelect = $('#preset_select');
203	    SC.PRESETS.forEach(function(preset) {
204	        $('<option>').val(preset.id).text(preset.label).appendTo($presetSelect);
205	    });
206	
207	    // ── Speed slider ───────────────────────────────────────────────────────
208	    $('#speed_slider').on('input change', function() {
209	        opsPerSecond = parseInt(this.value);
210	        $('#speed_label').text(opsPerSecond + ' ops/s');
211	    });
212	
213	    // ── Grid init ─────────────────────────────────────────────────────────
214	    function initGrid(w, h, sx, sy, ex, ey) {
215	        w  = w  || SC.GRID_SIZE_DEFAULT.width;
216	        h  = h  || SC.GRID_SIZE_DEFAULT.height;
217	        sx = (sx !== undefined) ? sx : 1;
218	        sy = (sy !== undefined) ? sy : Math.floor(h / 2);
219	        ex = (ex !== undefined) ? ex : w - 2;
220	        ey = (ey !== undefined) ? ey : Math.floor(h / 2);
221	
222	        if (!SC.validateGridSize(w, h)) {
223	            setStatus('Invalid grid size: must be 5–50.');
224	            return;
225	        }
226	
227	        startX = sx; startY = sy; endX = ex; endY = ey;
228	        grid = new PF.Grid(w, h);
229	        abortSearch();
230	
231	        View.init({ numCols: w, numRows: h });
232	        View.generateGrid(function() {
233	            View.setStartPos(startX, startY);
234	            View.setEndPos(endX, endY);
235	            bindDrawEvents();
236	        });
237	    }
238	
239	    // ── Draw events (wall drawing / dragging start+end) ────────────────────
240	    function bindDrawEvents() {
241	        var drawing = null; // 'wall' | 'erase' | 'dragStart' | 'dragEnd'
242	
243	        $('#draw_area').off('mousedown').on('mousedown', function(e) {
244	            if (isSearching) return;
245	            var coord = View.toGridCoordinate(e.pageX, e.pageY);
246	            var gx = coord[0], gy = coord[1];
247	
248	            if (gx === startX && gy === startY) { drawing = 'dragStart'; return; }
249	            if (gx === endX   && gy === endY)   { drawing = 'dragEnd';   return; }
250	
251	            if (grid.isWalkableAt(gx, gy)) {
252	                drawing = 'wall';
253	                setWalkable(gx, gy, false);
254	            } else {
255	                drawing = 'erase';
256	                setWalkable(gx, gy, true);
257	            }
258	        });
259	
260	        $(window).off('mousemove.sb').on('mousemove.sb', function(e) {
261	            if (!drawing) return;
262	            var coord = View.toGridCoordinate(e.pageX, e.pageY);
263	            var gx = coord[0], gy = coord[1];
264	            if (gx < 0 || gy < 0 || gx >= grid.width || gy >= grid.height) return;
265	
266	            if (drawing === 'dragStart' && grid.isWalkableAt(gx, gy) &&
267	                !(gx === endX && gy === endY)) {
268	                startX = gx; startY = gy;
269	                View.setStartPos(gx, gy);
270	            } else if (drawing === 'dragEnd' && grid.isWalkableAt(gx, gy) &&
271	                       !(gx === startX && gy === startY)) {
272	                endX = gx; endY = gy;
273	                View.setEndPos(gx, gy);
274	            } else if (drawing === 'wall' && !(gx === startX && gy === startY) &&
275	                       !(gx === endX && gy === endY)) {
276	                setWalkable(gx, gy, false);
277	            } else if (drawing === 'erase') {
278	                setWalkable(gx, gy, true);
279	            }
280	        });
281	
282	        $(window).off('mouseup.sb').on('mouseup.sb', function() {
283	            drawing = null;
284	        });
285	    }
286	
287	    function setWalkable(gx, gy, walkable) {
288	        grid.setWalkableAt(gx, gy, walkable);
289	        View.setAttributeAt(gx, gy, 'walkable', walkable);
290	    }
291	
292	    // ── Find Path ─────────────────────────────────────────────────────────
293	    hookNodeTracking();
294	
295	    function hookNodeTracking() {
296	        PF.Node.prototype = {
297	            get opened() { return this._opened; },
298	            set opened(v) {
299	                this._opened = v;
300	                operations.push({ x: this.x, y: this.y, attr: 'opened', value: v });
301	            },
302	            get closed() { return this._closed; },
303	            set closed(v) {
304	                this._closed = v;
305	                operations.push({ x: this.x, y: this.y, attr: 'closed', value: v });
306	            },
307	            get tested() { return this._tested; },
308	            set tested(v) {
309	                this._tested = v;
310	                operations.push({ x: this.x, y: this.y, attr: 'tested', value: v });
311	            },
312	        };
313	    }
314	
315	    function findPath() {
316	        if (!grid) return;
317	        abortSearch();
318	        View.clearFootprints && View.clearFootprints();
319	        View.clearPath && View.clearPath();
320	        operations = [];
321	
322	        var algoId  = $('#algo_select').val();
323	        var finder  = buildFinder(algoId);
324	        if (!finder) { setStatus('Unknown algorithm: ' + algoId); return; }
325	
326	        var cloned  = grid.clone();
327	        var path    = finder.findPath(startX, startY, endX, endY, cloned);
328	        var opsCopy = operations.slice();
329	        operations  = [];
330	
331	        isSearching = true;
332	        setStatus('Searching…');
333	
334	        var opIdx = 0;
335	        animTimer = setInterval(function() {
336	            if (opIdx >= opsCopy.length) {
337	                clearInterval(animTimer);
338	                isSearching = false;
339	                View.drawPath(path);
340	                if (path.length) {
341	                    setStatus('Path found · ' + path.length + ' nodes');
342	                } else {
343	                    setStatus('No path found');
344	                }
345	                return;
346	            }
347	            var op = opsCopy[opIdx++];
348	            if (View.supportedOperations.indexOf(op.attr) !== -1) {
349	                View.setAttributeAt(op.x, op.y, op.attr, op.value);
350	            }
351	        }, 1000 / opsPerSecond);
352	    }
353	
354	    function abortSearch() {
355	        if (animTimer) { clearInterval(animTimer); animTimer = null; }
356	        isSearching = false;
357	    }
358	
359	    function buildFinder(id) {
360	        switch (id) {
361	            case 'AStarFinder':          return new PF.AStarFinder();
362	            case 'BiAStarFinder':        return new PF.BiAStarFinder();
363	            case 'BestFirstFinder':      return new PF.BestFirstFinder();
364	            case 'BiBestFirstFinder':    return new PF.BiBestFirstFinder();
365	            case 'BreadthFirstFinder':   return new PF.BreadthFirstFinder();
366	            case 'BiBreadthFirstFinder': return new PF.BiBreadthFirstFinder();
367	            case 'DijkstraFinder':       return new PF.DijkstraFinder();
368	            case 'BiDijkstraFinder':     return new PF.BiDijkstraFinder();
369	            case 'IDAStarFinder':        return new PF.IDAStarFinder({ timeLimit: 10 });
370	            case 'JumpPointFinder':      return new PF.JumpPointFinder({
371	                diagonalMovement: PF.DiagonalMovement.IfAtMostOneObstacle
372	            });
373	            default: return null;
374	        }
375	    }
376	
377	    // ── Clear ─────────────────────────────────────────────────────────────
378	    function clearGrid() {
379	        if (!grid) return;
380	        abortSearch();
381	        var w = grid.width, h = grid.height;
382	        initGrid(w, h, startX, startY, endX, endY);
383	        setStatus('Grid cleared');
384	    }
385	
386	    // ── Resize ────────────────────────────────────────────────────────────
387	    function resizeGrid() {
388	        var w = parseInt($('#grid_width').val());
389	        var h = parseInt($('#grid_height').val());
390	        if (!SC.validateGridSize(w, h)) {
391	            setStatus('Invalid size: must be 5–50.');
392	            return;
393	        }
394	        initGrid(w, h);
395	    }
396	
397	    // ── Preset load ───────────────────────────────────────────────────────
398	    $('#preset_select').on('change', function() {
399	        var id = this.value;
400	        if (!id) return;
401	        var preset = SC.PRESETS.filter(function(p) { return p.id === id; })[0];
402	        if (!preset) return;
403	        loadScenario(preset.scenario);
404	        this.value = '';
405	        setStatus('Loaded preset: ' + preset.label);
406	    });
407	
408	    function loadScenario(data) {
409	        try {
410	            var restored = SC.deserializeGrid(data);
411	            var w = restored.grid.width, h = restored.grid.height;
412	            abortSearch();
413	            grid = restored.grid;
414	            startX = restored.startX; startY = restored.startY;
415	            endX   = restored.endX;   endY   = restored.endY;
416	
417	            $('#grid_width').val(w);
418	            $('#grid_height').val(h);
419	
420	            View.init({ numCols: w, numRows: h });
421	            View.generateGrid(function() {
422	                // Restore walls
423	                for (var y = 0; y < h; y++) {
424	                    for (var x = 0; x < w; x++) {
425	                        if (!grid.isWalkableAt(x, y)) {
426	                            View.setAttributeAt(x, y, 'walkable', false);
427	                        }
428	                    }
429	                }
430	                View.setStartPos(startX, startY);
431	                View.setEndPos(endX, endY);
432	                bindDrawEvents();
433	            });
434	        } catch (err) {
435	            setStatus('Load error: ' + err.message);
436	        }
437	    }
438	
439	    // ── Save Scenario ─────────────────────────────────────────────────────
440	    function saveScenario() {
441	        if (!grid) return;
442	        var data = SC.serializeGrid(grid, startX, startY, endX, endY);
443	        var json = JSON.stringify(data, null, 2);
444	        var blob = new Blob([json], { type: 'application/json' });
445	        var url  = URL.createObjectURL(blob);
446	        var a    = document.createElement('a');
447	        a.href     = url;
448	        a.download = 'scenario.json';
449	        document.body.appendChild(a);
450	        a.click();
451	        document.body.removeChild(a);
452	        URL.revokeObjectURL(url);
453	        setStatus('Scenario saved');
454	    }
455	
456	    // ── Load Scenario (file picker) ───────────────────────────────────────
457	    $('#btn_load').on('click', function() {
458	        $('#file_input').click();
459	    });
460	
461	    $('#file_input').on('change', function() {
462	        var file = this.files[0];
463	        if (!file) return;
464	        var reader = new FileReader();
465	        reader.onload = function(e) {
466	            try {
467	                var data = JSON.parse(e.target.result);
468	                loadScenario(data);
469	                setStatus('Loaded: ' + file.name);
470	            } catch (err) {
471	                setStatus('Invalid file: ' + err.message);
472	            }
473	        };
474	        reader.readAsText(file);
475	        this.value = '';
476	    });
477	
478	    // ── Button wiring ──────────────────────────────────────────────────────
479	    $('#btn_find_path').on('click', findPath);
480	    $('#btn_clear').on('click', clearGrid);
481	    $('#btn_save').on('click', saveScenario);
482	    $('#btn_apply_size').on('click', resizeGrid);
483	
484	    // ── Status helper ──────────────────────────────────────────────────────
485	    function setStatus(msg) {
486	        $('#status_bar').text(msg);
487	    }
488	
489	    // ── Boot ───────────────────────────────────────────────────────────────
490	    $(function() {
491	        initGrid(
492	            SC.GRID_SIZE_DEFAULT.width,
493	            SC.GRID_SIZE_DEFAULT.height
494	        );
495	    });
496	
497	}());
498	</script>
499	</body>
500	</html>
