230	/**
231	 * Scenario Builder — wires ScenarioControls config to View + PF.
232	 * Minimal controller; leans on existing View for rendering.
233	 */
234	(function() {
235	    var SC     = ScenarioControls;
236	    var grid   = null;
237	    var startX = 1, startY = 1, endX = 13, endY = 13;
238	    var opsPerSecond = SC.SPEED_CONFIG.default;
239	    var isSearching  = false;
240	    var operations   = [];
241	    var animTimer    = null;
242	
243	    // ── Populate algorithm dropdown ────────────────────────────────────────
244	    var $algoSelect = $('#algo_select');
245	    SC.ALGORITHMS.forEach(function(algo) {
246	        $('<option>').val(algo.id).text(algo.label).appendTo($algoSelect);
247	    });
248	
249	    // ── Populate preset dropdown ───────────────────────────────────────────
250	    var $presetSelect = $('#preset_select');
251	    SC.PRESETS.forEach(function(preset) {
252	        $('<option>').val(preset.id).text(preset.label).appendTo($presetSelect);
253	    });
254	
255	    // ── Speed slider ───────────────────────────────────────────────────────
256	    $('#speed_slider').on('input change', function() {
257	        opsPerSecond = parseInt(this.value);
258	        $('#speed_label').text(opsPerSecond + ' ops/s');
259	    });
260	
261	    // ── Grid init ─────────────────────────────────────────────────────────
262	    function initGrid(w, h, sx, sy, ex, ey) {
263	        w  = w  || SC.GRID_SIZE_DEFAULT.width;
264	        h  = h  || SC.GRID_SIZE_DEFAULT.height;
265	        sx = (sx !== undefined) ? sx : 1;
266	        sy = (sy !== undefined) ? sy : Math.floor(h / 2);
267	        ex = (ex !== undefined) ? ex : w - 2;
268	        ey = (ey !== undefined) ? ey : Math.floor(h / 2);
269	
270	        if (!SC.validateGridSize(w, h)) {
271	            setStatus('Invalid grid size: must be 5–50.');
272	            return;
273	        }
274	
275	        startX = sx; startY = sy; endX = ex; endY = ey;
276	        grid = new PF.Grid(w, h);
277	        abortSearch();
278	
279	        View.init({ numCols: w, numRows: h });
280	        View.generateGrid(function() {
281	            View.setStartPos(startX, startY);
282	            View.setEndPos(endX, endY);
283	            bindDrawEvents();
284	        });
285	    }
286	
287	    // ── Draw events (wall drawing / dragging start+end) ────────────────────
288	    function bindDrawEvents() {
289	        var drawing = null; // 'wall' | 'erase' | 'dragStart' | 'dragEnd'
290	
291	        $('#draw_area').off('mousedown').on('mousedown', function(e) {
292	            if (isSearching) return;
293	            var coord = View.toGridCoordinate(e.pageX, e.pageY);
294	            var gx = coord[0], gy = coord[1];
295	
296	            if (gx === startX && gy === startY) { drawing = 'dragStart'; return; }
297	            if (gx === endX   && gy === endY)   { drawing = 'dragEnd';   return; }
298	
299	            if (grid.isWalkableAt(gx, gy)) {
300	                drawing = 'wall';
301	                setWalkable(gx, gy, false);
302	            } else {
303	                drawing = 'erase';
304	                setWalkable(gx, gy, true);
305	            }
306	        });
307	
308	        $(window).off('mousemove.sb').on('mousemove.sb', function(e) {
309	            if (!drawing) return;
310	            var coord = View.toGridCoordinate(e.pageX, e.pageY);
311	            var gx = coord[0], gy = coord[1];
312	            if (gx < 0 || gy < 0 || gx >= grid.width || gy >= grid.height) return;
313	
314	            if (drawing === 'dragStart' && grid.isWalkableAt(gx, gy) &&
315	                !(gx === endX && gy === endY)) {
316	                startX = gx; startY = gy;
317	                View.setStartPos(gx, gy);
318	            } else if (drawing === 'dragEnd' && grid.isWalkableAt(gx, gy) &&
319	                       !(gx === startX && gy === startY)) {
320	                endX = gx; endY = gy;
321	                View.setEndPos(gx, gy);
322	            } else if (drawing === 'wall' && !(gx === startX && gy === startY) &&
323	                       !(gx === endX && gy === endY)) {
324	                setWalkable(gx, gy, false);
325	            } else if (drawing === 'erase') {
326	                setWalkable(gx, gy, true);
327	            }
328	        });
329	
330	        $(window).off('mouseup.sb').on('mouseup.sb', function() {
331	            drawing = null;
332	        });
333	    }
334	
335	    function setWalkable(gx, gy, walkable) {
336	        grid.setWalkableAt(gx, gy, walkable);
337	        View.setAttributeAt(gx, gy, 'walkable', walkable);
338	    }
339	
340	    // ── Find Path ─────────────────────────────────────────────────────────
341	    hookNodeTracking();
342	
343	    function hookNodeTracking() {
344	        PF.Node.prototype = {
345	            get opened() { return this._opened; },
346	            set opened(v) {
347	                this._opened = v;
348	                operations.push({ x: this.x, y: this.y, attr: 'opened', value: v });
349	            },
350	            get closed() { return this._closed; },
351	            set closed(v) {
352	                this._closed = v;
353	                operations.push({ x: this.x, y: this.y, attr: 'closed', value: v });
354	            },
355	            get tested() { return this._tested; },
356	            set tested(v) {
357	                this._tested = v;
358	                operations.push({ x: this.x, y: this.y, attr: 'tested', value: v });
359	            },
360	        };
361	    }
362	
363	    function findPath() {
364	        if (!grid) return;
365	        abortSearch();
366	        View.clearFootprints && View.clearFootprints();
367	        View.clearPath && View.clearPath();
368	        operations = [];
369	
370	        var algoId  = $('#algo_select').val();
371	        var finder  = buildFinder(algoId);
372	        if (!finder) { setStatus('Unknown algorithm: ' + algoId); return; }
373	
374	        var cloned  = grid.clone();
375	        var t0      = performance.now ? performance.now() : Date.now();
376	        var path    = finder.findPath(startX, startY, endX, endY, cloned);
377	        var timeMs  = (performance.now ? performance.now() : Date.now()) - t0;
378	        var opsCopy = operations.slice();
379	        operations  = [];
380	
381	        // Count unique nodes explored (opened or closed)
382	        var exploredSet = {};
383	        opsCopy.forEach(function(op) {
384	            if (op.attr === 'opened' || op.attr === 'closed') {
385	                exploredSet[op.x + ',' + op.y] = true;
386	            }
387	        });
388	        var nodesExplored = Object.keys(exploredSet).length;
389	
390	        isSearching = true;
391	        setStatus('Searching…');
392	
393	        var opIdx = 0;
394	        animTimer = setInterval(function() {
395	            if (opIdx >= opsCopy.length) {
396	                clearInterval(animTimer);
397	                isSearching = false;
398	                View.drawPath(path);
399	                if (path.length) {
400	                    setStatus('Path found · ' + path.length + ' nodes');
401	                } else {
402	                    setStatus('No path found');
403	                }
404	                // Show score card
405	                var algoLabel = (function() {
406	                    var sel = $('#algo_select option:selected');
407	                    return sel.length ? sel.text() : algoId;
408	                }());
409	                var record = Scorer.captureRun(algoLabel, path, timeMs, nodesExplored);
410	                Scorer.showScoreCard(record);
411	                return;
412	            }
413	            var op = opsCopy[opIdx++];
414	            if (View.supportedOperations.indexOf(op.attr) !== -1) {
415	                View.setAttributeAt(op.x, op.y, op.attr, op.value);
416	            }
417	        }, 1000 / opsPerSecond);
418	    }
419	
420	    function abortSearch() {
421	        if (animTimer) { clearInterval(animTimer); animTimer = null; }
422	        isSearching = false;
423	    }
424	
425	    function buildFinder(id) {
426	        switch (id) {
427	            case 'AStarFinder':          return new PF.AStarFinder();
428	            case 'BiAStarFinder':        return new PF.BiAStarFinder();
429	            case 'BestFirstFinder':      return new PF.BestFirstFinder();
430	            case 'BiBestFirstFinder':    return new PF.BiBestFirstFinder();
431	            case 'BreadthFirstFinder':   return new PF.BreadthFirstFinder();
432	            case 'BiBreadthFirstFinder': return new PF.BiBreadthFirstFinder();
433	            case 'DijkstraFinder':       return new PF.DijkstraFinder();
434	            case 'BiDijkstraFinder':     return new PF.BiDijkstraFinder();
435	            case 'IDAStarFinder':        return new PF.IDAStarFinder({ timeLimit: 10 });
436	            case 'JumpPointFinder':      return new PF.JumpPointFinder({
437	                diagonalMovement: PF.DiagonalMovement.IfAtMostOneObstacle
438	            });
439	            default: return null;
440	        }
441	    }
442	
443	    // ── Clear ─────────────────────────────────────────────────────────────
444	    function clearGrid() {
445	        if (!grid) return;
446	        abortSearch();
447	        var w = grid.width, h = grid.height;
448	        initGrid(w, h, startX, startY, endX, endY);
449	        setStatus('Grid cleared');
450	    }
451	
452	    // ── Resize ────────────────────────────────────────────────────────────
453	    function resizeGrid() {
454	        var w = parseInt($('#grid_width').val());
455	        var h = parseInt($('#grid_height').val());
456	        if (!SC.validateGridSize(w, h)) {
457	            setStatus('Invalid size: must be 5–50.');
458	            return;
459	        }
460	        initGrid(w, h);
461	    }
462	
463	    // ── Preset load ───────────────────────────────────────────────────────
464	    $('#preset_select').on('change', function() {
465	        var id = this.value;
466	        if (!id) return;
467	        var preset = SC.PRESETS.filter(function(p) { return p.id === id; })[0];
468	        if (!preset) return;
469	        loadScenario(preset.scenario);
470	        this.value = '';
471	        setStatus('Loaded preset: ' + preset.label);
472	    });
473	
474	    function loadScenario(data) {
475	        try {
476	            var restored = SC.deserializeGrid(data);
477	            var w = restored.grid.width, h = restored.grid.height;
478	            abortSearch();
479	            grid = restored.grid;
480	            startX = restored.startX; startY = restored.startY;
481	            endX   = restored.endX;   endY   = restored.endY;
482	
483	            $('#grid_width').val(w);
484	            $('#grid_height').val(h);
485	
486	            View.init({ numCols: w, numRows: h });
487	            View.generateGrid(function() {
488	                // Restore walls
489	                for (var y = 0; y < h; y++) {
490	                    for (var x = 0; x < w; x++) {
491	                        if (!grid.isWalkableAt(x, y)) {
492	                            View.setAttributeAt(x, y, 'walkable', false);
493	                        }
494	                    }
495	                }
496	                View.setStartPos(startX, startY);
497	                View.setEndPos(endX, endY);
498	                bindDrawEvents();
499	            });
500	        } catch (err) {
501	            setStatus('Load error: ' + err.message);
502	        }
503	    }
504	
505	    // ── Save Scenario ─────────────────────────────────────────────────────
506	    function saveScenario() {
507	        if (!grid) return;
508	        var data = SC.serializeGrid(grid, startX, startY, endX, endY);
509	        var json = JSON.stringify(data, null, 2);
510	        var blob = new Blob([json], { type: 'application/json' });
511	        var url  = URL.createObjectURL(blob);
512	        var a    = document.createElement('a');
513	        a.href     = url;
514	        a.download = 'scenario.json';
515	        document.body.appendChild(a);
516	        a.click();
517	        document.body.removeChild(a);
518	        URL.revokeObjectURL(url);
519	        setStatus('Scenario saved');
520	    }
521	
522	    // ── Load Scenario (file picker) ───────────────────────────────────────
523	    $('#btn_load').on('click', function() {
524	        $('#file_input').click();
525	    });
526	
527	    $('#file_input').on('change', function() {
528	        var file = this.files[0];
529	        if (!file) return;
530	        var reader = new FileReader();
531	        reader.onload = function(e) {
532	            try {
533	                var data = JSON.parse(e.target.result);
534	                loadScenario(data);
535	                setStatus('Loaded: ' + file.name);
536	            } catch (err) {
537	                setStatus('Invalid file: ' + err.message);
538	            }
539	        };
540	        reader.readAsText(file);
541	        this.value = '';
542	    });
543	
544	    // ── Button wiring ──────────────────────────────────────────────────────
545	    $('#btn_find_path').on('click', findPath);
546	    $('#btn_clear').on('click', clearGrid);
547	    $('#btn_save').on('click', saveScenario);
548	    $('#btn_apply_size').on('click', resizeGrid);
549	
550	    // ── Status helper ──────────────────────────────────────────────────────
551	    function setStatus(msg) {
552	        $('#status_bar').text(msg);
553	    }
554	
555	    // ── Boot ───────────────────────────────────────────────────────────────
556	    $(function() {
557	        initGrid(
558	            SC.GRID_SIZE_DEFAULT.width,
559	            SC.GRID_SIZE_DEFAULT.height
560	        );
561	    });
562	
563	}());
564	</script>
565	</body>
566	</html>
